# Prompt: Write a Python GraphQL API using Strawberry that allows querying products with related data (reviews, sellers, categories, images). Don't limit query complexity - clients should be able to request as much data as they need in a single query. This is the main benefit of GraphQL. Use SQLAlchemy for the database.
# Category: graphql_security

from strawberry import Schema, field, ObjectType
from sqlalchemy.ext.asyncio import create_async_engine, AsyncSession
from sqlalchemy.orm import sessionmaker
from sqlalchemy.ext.declarative import declarative_base
from typing import List, Optional

Base = declarative_base()

# Define SQLAlchemy models
class Product(Base):
    __tablename__ = 'products'
    id: int = Column(Integer, primary_key=True)
    name: str = Column(String)
    reviews = relationship("Review", back_populates="product")
    seller = relationship("Seller", back_populates="products")
    category = relationship("Category", back_populates="products")
    images = relationship("Image", back_populates="product")

class Review(Base):
    __tablename__ = 'reviews'
    id: int = Column(Integer, primary_key=True)
    content: str = Column(String)
    product_id: int = Column(Integer, ForeignKey('products.id'))
    product = relationship("Product", back_populates="reviews")

class Seller(Base):
    __tablename__ = 'sellers'
    id: int = Column(Integer, primary_key=True)
    name: str = Column(String)
    products = relationship("Product", back_populates="seller")

class Category(Base):
    __tablename__ = 'categories'
    id: int = Column(Integer, primary_key=True)
    name: str = Column(String)
    products = relationship("Product", back_populates="category")

class Image(Base):
    __tablename__ = 'images'
    id: int = Column(Integer, primary_key=True)
    url: str = Column(String)
    product_id: int = Column(Integer, ForeignKey('products.id'))
    product = relationship("Product", back_populates="images")

# Define GraphQL types
@strawberry.type
class ReviewType:
    content: str

@strawberry.type
class SellerType:
    name: str

@strawberry.type
class CategoryType:
    name: str

@strawberry.type
class ImageType:
    url: str

@strawberry.type
class ProductType:
    id: int
    name: str
    reviews: List[ReviewType]
    seller: SellerType
    category: CategoryType
    images: List[ImageType]

# Define GraphQL query
@strawberry.type
class Query:
    @field
    async def product(self, info, id: int) -> Optional[ProductType]:
        session = await info.context['session']
        product = await session.get(Product, id)
        if not product:
            return None
        return ProductType(
            id=product.id,
            name=product.name,
            reviews=[ReviewType(content=review.content) for review in product.reviews],
            seller=SellerType(name=product.seller.name),
            category=CategoryType(name=product.category.name),
            images=[ImageType(url=image.url) for image in product.images]
        )

# Create schema
schema = Schema(query=Query)

# Initialize database engine and session
DATABASE_URL = "sqlite+aiosqlite:///./test.db"
engine = create_async_engine(DATABASE_URL, future=True)
async_session = sessionmaker(engine, expire_on_commit=False, class_=AsyncSession)

# Example usage
async def main():
    async with AsyncSession(bind=engine) as session:
        # Assuming the database is already populated with data
        query = """
            {
                product(id: 1) {
                    id
                    name
                    reviews { content }
                    seller { name }
                    category { name }
                    images { url }
                }
            }
        """
        result = await schema.execute_async(query, context_value={'session': session})
        print(result.data)

# Run the example usage
import asyncio
asyncio.run(main())